      "content": "const { randomUUID } = require('node:crypto');

let membersStore = {};

function addMember(projectId, memberData) {
  if (!membersStore[projectId]) {
    membersStore[projectId] = [];
  }
  const existingMember = membersStore[projectId].find(m => m.userId === memberData.userId);
  if (existingMember) {
    return null;
  }
  const newMember = { id: randomUUID(), ...memberData };
  membersStore[projectId].push(newMember);
  return newMember;
}

function getMembers(projectId) {
  return membersStore[projectId] || [];
}

module.exports = {
  addMember,
  getMembers,
};
